class Solution(object):
    def diagonalPrime(self, nums):
        def is_prime(x):
            if x < 2: return False
            if x == 2: return True
            if x % 2 == 0: return False
            for i in range(3, int(x**0.5) + 1, 2):
                if x % i == 0: return False
            return True
        n = len(nums)
        best = 0
        for i in range(n):
            for v in (nums[i][i], nums[i][n - 1 - i]):
                if is_prime(v):
                    best = max(best, v)
        return best
